return-response.set-body:
@{
                    return new JObject(
                        new JProperty("error", "unauthorized"),
                        new JProperty("message", "JWT validation failed. Confirm tenantId, audience, and client-application-id."),
                        new JProperty("correlationId", context.RequestId)
                    ).ToString();
                }

@{
                            return new JObject(
                                new JProperty("error", "quota_exceeded"),
                                new JProperty("message", "Hourly token quota exhausted for this identity."),
                                new JProperty("correlationId", context.RequestId)
                            ).ToString();
                        }

@{
                            return new JObject(
                                new JProperty("error", "rate_limited"),
                                new JProperty("message", "Tokens-per-minute limit reached for this identity."),
                                new JProperty("retryAfterSeconds", context.Response.Headers.GetValueOrDefault("Retry-After","30")),
                                new JProperty("correlationId", context.RequestId)
                            ).ToString();
                        }

@{
                    return new JObject(
                        new JProperty("error", "internal_error"),
                        new JProperty("message", "An unexpected error occurred in the APIM gateway."),
                        new JProperty("correlationId", context.RequestId)
                    ).ToString();
                }
